INSERT INTO diaries (id,user_id,date,write_type,emotion_type,content) VALUES (3,2,'2025-10-03','STT','SADNESS','랩실에서 교수님과 잠깐 상담했다. 버스를 타고 오는데 날씨가 생각보다 선선했다. 잠깐 산책을 하면서 머리를 식혔다. 팀플 관련 회의를 짧게 진행했다. 스터디 친구들과 문제를 함께 풀었다. 카페에서 코딩을 하면서 음악을 들었다. 집에 와서 프로젝트 코드를 정리했다.');
