INSERT INTO diaries (id,user_id,date,write_type,emotion_type,content) VALUES (37,2,'2025-11-06','STT','SENSITIVE','잠깐 산책을 하면서 머리를 식혔다. 스터디 친구들과 문제를 함께 풀었다. 오전엔 강의가 많아서 조금 지쳤다. 버스를 타고 오는데 날씨가 생각보다 선선했다. 도서관에서 과제를 조금 정리했다. 팀플 관련 회의를 짧게 진행했다. 카페에서 코딩을 하면서 음악을 들었다. 집에 와서 프로젝트 코드를 정리했다. 오늘 학교에서 전공 수업을 들었다. 랩실에서 교수님과 잠깐 상담했다.');
INSERT INTO analysis (id,user_id,diary_id,birth_year,analysis_date) VALUES (37,2,37,2000,'2025-11-06');
INSERT INTO analysis_result (id,analysis_id,emotion_label,emotion_score,emotion_reason,music_json) VALUES (37,37,'SENSITIVE',0.82,'일기 분석 기반 감정','[{"title": "Comfort Song", "artist": "LoFi Artist", "genre": "lofi"}]');
INSERT INTO user_challenge (id,user_id,challenge_id,date,is_completed) VALUES (37,2,1,'2025-11-06',false);
