INSERT INTO diaries (id,user_id,date,write_type,emotion_type,content) VALUES (41,3,'2025-10-01','STT','SENSITIVE','잠깐 들른 전시회에서 마음이 힐링됐다. 작업 마감 때문에 집중해서 일했다. 회사에서 프로젝트 미팅이 있었다. 출근길에 지하철이 조금 붐볐다. 오랜만에 회사 근처 공원을 걸었다. 퇴근 후 잠깐 카페에 들러 쉬었다. 오후 업무가 길어져 조금 피곤했다. 메일을 정리하다가 중요한 일정이 생겼다. 점심시간에 동료와 맛있는 식사를 했다.');
